import React, { useEffect, useState } from "react";
import axios from "axios";
import "./LabSearch.css";

const LabSearch = ({ goBack }) => {
  const [selectedLab, setSelectedLab] = useState("");
  const [labList, setLabList] = useState([]);
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");

  useEffect(() => {
    // Fetch lab rooms from backend
    axios.get("http://localhost:5000/api/lab-list")
      .then((res) => {
        setLabList(res.data);
        if (res.data.length > 0) setSelectedLab(res.data[0].name);
      })
      .catch((err) => console.error("Error fetching lab list:", err));
  }, []);

  const handleSearch = async () => {
    setResult(null);
    setError("");

    if (!selectedLab) {
      setError("Please select a lab.");
      return;
    }

    try {
      const response = await axios.get("http://localhost:5000/api/check-lab", {
        params: { room: selectedLab },
      });
      setResult(response.data);
    } catch (err) {
      console.error("Error fetching lab availability:", err);
      setError("Lab not found or server error.");
    }
  };

  return (
    <div className="lab-search-layout">
      {/* Left side: search form */}
      <div className="lab-search-container">
        <h2>Check Lab Availability</h2>
        <div className="search-filters">
          <div className="search-row">
            <label>Lab Room:</label>
            <select value={selectedLab} onChange={(e) => setSelectedLab(e.target.value)}>
              {labList.map((lab, index) => (
                <option key={index} value={lab.name}>{lab.name}</option>
              ))}
            </select>
          </div>
          <div className="button-group">
            <button onClick={handleSearch}>Search</button>
            <button onClick={goBack}>Back</button>
          </div>
        </div>
        {error && <p className="error">{error}</p>}
        {result && (
          <div className="result">
            <h3>Lab Availability</h3>
            <p><strong>Status:</strong> {result.occupied ? "Occupied" : "Free"}</p>
            {result.occupied && <p><strong>Faculty:</strong> {result.faculty}</p>}
          </div>
        )}
      </div>

      {/* Right side: lab list */}
      <div className="lab-list-container">
        <h3>Lab List</h3>
        <ul className="lab-list">
          {labList.map((lab, index) => (
            <li key={index} className="lab-item">
              <span>{lab.name}</span>
              <button className="plus-button" onClick={() => setSelectedLab(lab.name)}>+</button>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default LabSearch;
